mapper.select:
SELECT count(1) FROM ( SELECT MAX(id) AS id, DATE(FROM_UNIXTIME(ss.created_time / 1000)) AS dateStr, ss.site_code AS siteCode, ss.site_name AS siteName, ss.company_name AS companyName, ss.site_type AS siteType, ss.currency_code AS currencyCode, SUM(ss.new_members) AS newMembers, SUM(ss.first_deposit_count) AS firstDepositCount, SUM(ss.first_deposit_amount) AS firstDepositAmount, SUM(ss.deposit_amount) AS depositAmount, SUM(ss.deposit_count) AS depositCount, SUM(ss.withdrawal_amount) AS withdrawalAmount, SUM(ss.withdrawal_count) AS withdrawalCount, SUM(ss.large_withdrawal_count) AS largeWithdrawalCount, SUM(ss.deposit_withdrawal_difference) AS depositWithdrawalDifference, SUM(ss.site_vip_benefits) AS siteVipBenefits, SUM(ss.site_promotional_offers) AS sitePromotionalOffers, SUM(ss.site_used_offers) AS siteUsedOffers, SUM(ss.site_other_adjustments) AS siteOtherAdjustments, SUM(ss.bet_count) AS betCount, SUM(ss.betting_amount) AS bettingAmount, SUM(ss.valid_betting) AS validBetting, SUM(ss.member_profit_loss) AS memberProfitLoss, SUM(ss.net_profit) AS netProfit FROM report_site_statistics ss WHERE ss.created_time BETWEEN #{vo.startTime} AND #{vo.endTime}
AND ss.site_code = #{vo.siteCode}
AND ss.site_name = #{vo.siteName}
AND ss.site_type = #{vo.siteType}
AND ss.currency_code = #{vo.currencyCode}
GROUP BY DATE(FROM_UNIXTIME(ss.created_time / 1000)), ss.site_code, ss.site_name, ss.company_name, ss.site_type, ss.currency_code ) t
